import json
import base64

payloads = {
    "arkhe_v14_0_0_agi.py": "",
    "substrate.toml": ""
}

def canonize():
    report = {
        "substrate_id": "1500",
        "name": "Cathedral ARKHE v14.0.0 — SUBSTRATO 1500",
        "status": "CANONIZED_FULL",
        "seal": "CATHEDRAL-ARKHE-v14.0.0-SUBSTRATO1500-2026-06-14",
        "Files": {}
    }
    for file_path, content in payloads.items():
        report["Files"][file_path] = base64.b64decode(content).decode("utf-8")
    return json.dumps(report, indent=2)

if __name__ == "__main__":
    print(canonize())
